110→func initDatabase() error {
111→	if config.Keys.DbConfig != nil {
112→		cfg := repository.DefaultConfig()
113→		dc := config.Keys.DbConfig
114→		if dc.CacheSizeMB > 0 {
115→			cfg.DbCacheSizeMB = dc.CacheSizeMB
116→		}
117→		if dc.SoftHeapLimitMB > 0 {
118→			cfg.DbSoftHeapLimitMB = dc.SoftHeapLimitMB
119→		}
120→		if dc.MaxOpenConnections > 0 {
121→			cfg.MaxOpenConnections = dc.MaxOpenConnections
122→		}
123→		if dc.MaxIdleConnections > 0 {
124→			cfg.MaxIdleConnections = dc.MaxIdleConnections
125→		}
126→		if dc.ConnectionMaxIdleTimeMins > 0 {
127→			cfg.ConnectionMaxIdleTime = time.Duration(dc.ConnectionMaxIdleTimeMins) * time.Minute
128→		}
129→		if dc.BusyTimeoutMs > 0 {
130→			cfg.BusyTimeoutMs = dc.BusyTimeoutMs
131→		}
132→		repository.SetConfig(cfg)
133→	}
134→	repository.Connect(config.Keys.DB)
135→	return nil
