138→func handleDatabaseCommands() error {
139→	if flagMigrateDB {
140→		err := repository.MigrateDB(config.Keys.DB)
141→		if err != nil {
142→			return fmt.Errorf("migrating database to version %d: %w", repository.Version, err)
143→		}
144→		cclog.Exitf("MigrateDB Success: Migrated SQLite database at '%s' to version %d.\n",
145→			config.Keys.DB, repository.Version)
146→	}
147→
148→	if flagRevertDB {
149→		err := repository.RevertDB(config.Keys.DB)
150→		if err != nil {
151→			return fmt.Errorf("reverting database to version %d: %w", repository.Version-1, err)
152→		}
