225→func addUser(userSpec string) error {
226→	parts := strings.SplitN(userSpec, ":", 3)
227→	if len(parts) != 3 || len(parts[0]) == 0 {
228→		return fmt.Errorf("invalid user format, want: <username>:[admin,support,manager,api,user]:<password>, have: %s", userSpec)
229→	}
230→
231→	ur := repository.GetUserRepository()
232→	if err := ur.AddUser(&schema.User{
233→		Username: parts[0],
234→		Projects: make([]string, 0),
235→		Password: parts[2],
236→		Roles:    strings.Split(parts[1], ","),
237→	}); err != nil {
238→		return fmt.Errorf("adding user '%s' with roles '%s': %w", parts[0], parts[1], err)
239→	}
240→
241→	cclog.Infof("Add User: Added new user '%s' with roles '%s'", parts[0], parts[1])
242→	return nil
243→}
