267→func generateJWT(authHandle *auth.Authentication, username string) error {
268→	ur := repository.GetUserRepository()
269→	user, err := ur.GetUser(username)
270→	if err != nil {
271→		return fmt.Errorf("getting user '%s': %w", username, err)
272→	}
273→
274→	if !user.HasRole(schema.RoleAPI) {
275→		cclog.Warnf("JWT: User '%s' does not have the role 'api'. REST API endpoints will return error!\n", user.Username)
276→	}
277→
278→	jwt, err := authHandle.JwtAuth.ProvideJWT(user)
279→	if err != nil {
280→		return fmt.Errorf("generating JWT for user '%s': %w", user.Username, err)
281→	}
282→
283→	cclog.Printf("JWT: Successfully generated JWT for user '%s': %s\n", user.Username, jwt)
284→	return nil
285→}
