291→		cclog.Warnf("initializing (optional) nats client: %s", err.Error())
292→	}
293→	nats.Connect()
294→
295→	// Initialize job archive
296→	archiveCfg := ccconf.GetPackageConfig("archive")
297→	if archiveCfg == nil {
298→		cclog.Debug("Archive configuration not found, using default archive configuration")
299→		archiveCfg = json.RawMessage(defaultArchiveConfig)
300→	}
301→	if err := archive.Init(archiveCfg); err != nil {
302→		return fmt.Errorf("initializing archive: %w", err)
303→	}
304→
305→	// Handle database re-initialization
306→	if flagReinitDB {
307→		if err := importer.InitDB(); err != nil {
308→			return fmt.Errorf("re-initializing repository DB: %w", err)
309→		}
310→		cclog.Print("Init DB: Successfully re-initialized repository DB.")
311→	}
312→
313→	// Handle job import
314→	if flagImportJob != "" {
315→		if err := importer.HandleImportFlag(flagImportJob); err != nil {
316→			return fmt.Errorf("importing job: %w", err)
317→		}
318→		cclog.Infof("Import Job: Imported Job '%s' into DB", flagImportJob)
319→	}
320→
321→	// Initialize taggers
322→	if config.Keys.EnableJobTaggers {
323→		tagger.Init()
324→	}
325→
326→	// Apply tags if requested
327→	if flagApplyTags {
328→		tagger.Init()
329→
330→		if err := tagger.RunTaggers(); err != nil {
331→			return fmt.Errorf("running job taggers: %w", err)
332→		}
333→	}
334→
335→	return nil
336→}
337→
338→func runServer(ctx context.Context) error {
339→	var wg sync.WaitGroup
340→
341→	// Initialize metric store if configuration is provided
342→	haveMetricstore := false
343→	mscfg := ccconf.GetPackageConfig("metric-store")
344→	if mscfg != nil {
345→		metrics := metricstore.BuildMetricList()
346→		metricstore.Init(mscfg, metrics, &wg)
347→
348→		// Inject repository as NodeProvider to break import cycle
349→		ms := metricstore.GetMemoryStore()
350→		jobRepo := repository.GetJobRepository()
351→		ms.SetNodeProvider(jobRepo)
352→		metricstore.MetricStoreHandle = &metricstore.InternalMetricStore{}
353→		haveMetricstore = true
354→	} else {
355→		metricstore.MetricStoreHandle = nil
356→		cclog.Debug("missing internal metricstore configuration")
357→	}
358→
359→	// Initialize external metric stores if configuration is provided
360→	mscfg = ccconf.GetPackageConfig("metric-store-external")
361→	if mscfg != nil {
362→		err := metricdispatch.Init(mscfg)
363→
364→		if err != nil {
365→			cclog.Debugf("error while initializing external metricdispatch: %v", err)
366→		} else {
367→			haveMetricstore = true
368→		}
369→	}
370→
371→	if !haveMetricstore {
372→		return fmt.Errorf("missing metricstore configuration")
373→	}
374→
375→	// Start archiver and task manager
376→	archiver.Start(repository.GetJobRepository(), ctx)
377→	taskmanager.Start(ccconf.GetPackageConfig("cron"), ccconf.GetPackageConfig("archive"))
378→
379→	// Initialize web UI
380→	cfg := ccconf.GetPackageConfig("ui")
381→	if err := web.Init(cfg); err != nil {
382→		return fmt.Errorf("initializing web UI: %w", err)
383→	}
384→
385→	// Initialize HTTP server
386→	srv, err := NewServer(version, commit, date)
387→	if err != nil {
388→		return fmt.Errorf("creating server: %w", err)
389→	}
390→
391→	// Channel to collect errors from server
392→	errChan := make(chan error, 1)
393→
394→	// Start HTTP server
395→	wg.Go(func() {
396→		if err := srv.Start(ctx); err != nil {
397→			errChan <- err
398→		}
399→	})
400→
401→	// Handle shutdown signals
402→	wg.Add(1)
403→	sigs := make(chan os.Signal, 1)
404→	signal.Notify(sigs, syscall.SIGINT, syscall.SIGTERM)
405→	go func() {
406→		defer wg.Done()
407→		select {
408→		case <-sigs:
409→			cclog.Info("Shutdown signal received")
410→		case <-ctx.Done():
411→		}
412→
413→		runtime.SystemdNotify(false, "Shutting down ...")
414→		srv.Shutdown(ctx)
415→		util.FsWatcherShutdown()
416→		taskmanager.Shutdown()
417→	}()
418→
419→	// Set GC percent if not configured
420→	if os.Getenv(envGOGC) == "" {
421→		// trigger GC when heap grows 15% above the previous live set
422→		debug.SetGCPercent(15)
423→	}
424→	runtime.SystemdNotify(true, "running")
425→
426→	waitDone := make(chan struct{})
427→	go func() {
428→		wg.Wait()
429→		close(waitDone)
430→	}()
431→
432→	go func() {
433→		<-waitDone
434→		close(errChan)
435→	}()
436→
437→	// Wait for either:
438→	// 1. An error from server startup
439→	// 2. Completion of all goroutines (normal shutdown or crash)
440→	select {
441→	case err := <-errChan:
442→		// errChan will be closed when waitDone is closed, which happens
443→		// when all goroutines complete (either from normal shutdown or error)
444→		if err != nil {
445→			return err
446→		}
447→	case <-time.After(100 * time.Millisecond):
448→		// Give the server 100ms to start and report any immediate startup errors
449→		// After that, just wait for normal shutdown completion
450→		select {
451→		case err := <-errChan:
452→			if err != nil {
453→				return err
454→			}
455→		case <-waitDone:
456→			// Normal shutdown completed
457→		}
458→	}
459→
460→	cclog.Print("Graceful shutdown completed!")
461→	return nil
462→}
463→
464→func run() error {
465→	cliInit()
466→
467→	if flagVersion {
468→		printVersion()
469→		return nil
470→	}
471→
472→	// Initialize logger
473→	cclog.Init(flagLogLevel, flagLogDateTime)
474→
475→	// Handle init flag
476→	if flagInit {
477→		initEnv()
478→		cclog.Exit("Successfully setup environment!\n" +
479→			"Please review config.json and .env and adjust it to your needs.\n" +
480→			"Add your job-archive at ./var/job-archive.")
481→	}
482→
483→	// Initialize gops agent
484→	if err := initGops(); err != nil {
485→		return err
486→	}
487→
488→	// Initialize subsystems in dependency order:
489→	// 1. Load environment variables from .env file (contains sensitive configuration)
